def run_backtest(data, idx, func, name):
    print(f"\n🔄 {name}...")
    eng = BacktestEngine(INIT_CASH)

    days = sorted(idx['date'].unique())
    cur_stocks = []
    cur_month = None
    rebalances = 0

    for date in days:
        # 每月调仓
        month = date[:7]
        if month != cur_month:
            cur_month = month
            new = func(data, date, 5)
            rebalances += 1

            # 卖出不在新名单的
            for s in cur_stocks:
                if s not in new:
                    df = data.get(s)
                    if df is not None:
                        r = df[df['date'] == date]
                        if len(r) > 0:
                            eng.sell(s, float(r['close'].iloc[0]), eng.positions.get(s, 0))

